import React, {useEffect, useState} from "react";
import axios from "axios";

const API = "http://http://localhost:5064/api"

interface Experience {
    experienceId : number;
    titre : string;
    description : string;
    entreprises : string;
    dateDebut : Date;
    dateFin : Date | null;
    competences : string[];
}

export default function Experiences(){

    const fetchExperiences = async () => {

        const [experiences, setExperiences] = useState<Experience[]>([]);

        useEffect(() => {
            fetchExperiences().catch();
        }, []);

        try {
            const reponse = await axios.get<Experience[]>(`${API}/experience`);
            console.log("données des experiences :", reponse.data);
        } catch (error) {
            console.log("erreur lors de la récupération des projets", error);
        }
    }


    return (
        <div>
            <h2>Liste des Expériences</h2>
            <ul>
                {Experiences.length === 0 ? (
                    <li>Aucune expérience trouvée.</li>
                ) : (
                    Experiences.map((exp) => (
                        <li key={exp.experienceId}>
                            <h3>{exp.titre}</h3>
                            <p>{exp.description}</p>
                            <p>Entreprise : {exp.entreprises}</p>
                            <p>
                                Durée :{" "}
                                {new Date(exp.dateDebut).toLocaleDateString()} -{" "}
                                {exp.dateFin
                                    ? new Date(exp.dateFin).toLocaleDateString()
                                    : "En cours"}
                            </p>
                            <p>Compétences : {exp.competences.join(", ")}</p>
                            <hr />
                        </li>
                    ))
                )}
            </ul>
        </div>
    )
}
